SELECT prgrm_id, sys_se_cd, prgrm_nm, prgrm_url, api_path_prefix, prgrm_desc, use_bgng_dt, use_end_dt, frst_reg_dt, frst_reg_user_id, last_chg_dt, last_chg_user_id FROM com.tn_prgrm WHERE NOW() BETWEEN use_bgng_dt AND use_end_dt
AND sys_se_cd = #{sysSeCd}
ORDER BY sys_se_cd, prgrm_id

SELECT EXISTS(
    SELECT 1
      FROM com.tn_prgrm
     WHERE prgrm_id = #{prgrmId}
)

mapper.update:
UPDATE com.tn_prgrm
   SET use_end_dt      = NOW() - INTERVAL '1 minute',
       last_chg_dt     = NOW(),
       last_chg_user_id = #{userId}
 WHERE prgrm_id = #{prgrmId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
